const SmartScanModal: React.FC = memo(() => {
    const dispatch = useAppDispatch();
    const videoRef = useRef<HTMLVideoElement>(null);
    const [stream, setStream] = useState<MediaStream | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const startCamera = useCallback(async () => {
        try {
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                setError("Kamera wird von diesem Browser nicht unterstützt.");
                return;
            }
            const mediaStream = await navigator.mediaDevices.getUserMedia({ 
                video: { 
                    facingMode: 'environment',
                    width: { ideal: 1280 },
                    height: { ideal: 720 }
                } 
            });
            setStream(mediaStream);
            if (videoRef.current) {
                videoRef.current.srcObject = mediaStream;
            }
        } catch (err) {
            console.error("Camera Error:", err);
            setError("Kamerazugriff verweigert.");
        }
    }, []);

    useEffect(() => {
        startCamera();
        return () => {
            stream?.getTracks().forEach(track => track.stop());
        };
    }, [startCamera]);

    const handleScan = useCallback(async () => {
        if (!videoRef.current) return;

        triggerHapticFeedback('medium');
        setIsLoading(true);
        setError(null);

        const canvas = document.createElement('canvas');
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        const ctx = canvas.getContext('2d');
        if (!ctx) {
            setIsLoading(false);
            return;
        }
        ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const base64Data = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];

        try {
            const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: [{
                    parts: [
                        { text: "Analysiere diesen Kassenbeleg. Extrahiere Händlername, Bruttobetrag und Datum. Antworte strikt im JSON Format." },
                        { inlineData: { mimeType: 'image/jpeg', data: base64Data } }
                    ]
                }],
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            description: { type: Type.STRING },
                            amount: { type: Type.NUMBER },
                            date: { type: Type.STRING },
                        },
                        required: ["description", "amount", "date"]
                    },
                },
            });

            const result = JSON.parse(response.text);
            triggerHapticFeedback('success');

            dispatch({ type: 'ADD_TRANSACTION', payload: {
                description: result.description || 'Scan',
                amount: result.amount || 0,
                date: result.date || new Date().toISOString().split('T')[0],
                type: TransactionType.EXPENSE,
                tags: ['gescannt']
            }});
        } catch (e) {
            triggerHapticFeedback('error');
            setError("Beleg konnte nicht gelesen werden.");
        } finally {
            setIsLoading(false);
        }
    }, [dispatch]);

    return (
        <div className="space-y-4">
            {error && <div className="p-3 bg-destructive/10 text-destructive text-sm rounded-lg border border-destructive/20">{error}</div>}
            <div className="relative aspect-[3/4] bg-black rounded-2xl overflow-hidden shadow-inner border border-border/20">
                <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                <div className="absolute inset-0 pointer-events-none border-[40px] border-black/40"></div>
                <div className="absolute inset-x-[40px] inset-y-[40px] border-2 border-primary/50 rounded-lg"></div>

                {isLoading && (
                    <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center animate-fade-in">
                        <div className="relative">
                            <Sparkles className="h-12 w-12 text-primary animate-pulse" />
                            <div className="absolute inset-0 animate-ping rounded-full bg-primary/20"></div>
                        </div>
                        <p className="mt-4 font-bold text-white">KI Analyse läuft...</p>
                    </div>
                )}
            </div>
            <div className="flex flex-col items-center gap-2">
                <Button 
                    onClick={handleScan} 
                    disabled={isLoading || !stream} 
                    variant="primary" 
                    className="w-full py-6 rounded-2xl text-lg shadow-xl"
                >
                    <Camera className="mr-2" /> Beleg scannen
                </Button>
                <p className="text-xs text-muted-foreground">Halten Sie den Beleg flach und mittig ins Bild.</p>
            </div>
        </div>
    );
});

