    const initialFormData = useMemo(() => ({ name: '', type: LiabilityType.DEBT, initialAmount: 0, interestRate: 0, minMonthlyPayment: 0 }), []);
    const [formData, setFormData] = useState<Omit<Liability, 'id' | 'paidAmount'>>(initialFormData);

    useEffect(() => {
        if (editingId) {
            const l = liabilities.find(l => l.id === editingId);
            if (l) { const { id, paidAmount, ...data } = l; setFormData(data); }
        } else setFormData(initialFormData);
    }, [editingId, liabilities, initialFormData]);

    const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        const numFields = ['initialAmount', 'interestRate', 'minMonthlyPayment'];
        setFormData(prev => ({ ...prev, [name]: numFields.includes(name) ? parseFloat(value) || 0 : value }));
    }, []);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        triggerHapticFeedback('success');
        if (editingId) {
            const original = liabilities.find(l => l.id === editingId)!;
            dispatch({ type: 'UPDATE_LIABILITY', payload: { ...formData, id: editingId, paidAmount: original.paidAmount } });
        } else {
            dispatch({ type: 'ADD_LIABILITY', payload: formData });
        }
        setEditingId(null);
    };

    const handleDelete = (id: string) => {
        if (window.confirm('Verbindlichkeit wirklich löschen?')) {
            triggerHapticFeedback('heavy');
            dispatch({ type: 'DELETE_LIABILITY', payload: id });
        }
    };

    return (
        <div className="space-y-6">
            <form onSubmit={handleSubmit} className="p-4 bg-secondary/50 rounded-lg space-y-4">
                <FormGroup label="Name"><Input name="name" value={formData.name} onChange={handleChange} required /></FormGroup>
                <div className="grid md:grid-cols-2 gap-4">
                    <FormGroup label="Typ"><Select name="type" value={formData.type} onChange={handleChange}><option value={LiabilityType.DEBT}>Schuld</option><option value={LiabilityType.LOAN}>Forderung</option></Select></FormGroup>
                    <FormGroup label="Anfangsbetrag"><Input type="number" name="initialAmount" value={formData.initialAmount} onChange={handleChange} required step="0.01" /></FormGroup>
                </div>
                <div className="flex items-center justify-end gap-2 pt-2">
                    {editingId && <Button type="button" onClick={() => setEditingId(null)}>Abbrechen</Button>}
                    <Button type="submit" variant="primary">Speichern</Button>
                </div>
            </form>
            <div className="space-y-2">
                {liabilities.map(l => (
                    <div key={l.id} className="p-3 rounded-xl flex items-center gap-4 bg-secondary/10">
                        <div className="flex-grow">
                            <p className="font-semibold text-sm">{l.name}</p>
                            <p className="text-xs text-muted-foreground">{formatCurrency(l.initialAmount - l.paidAmount)} offen</p>
                        </div>
                        <div className="flex items-center gap-1">
                            <Button onClick={() => setEditingId(l.id)} variant="secondary" className="p-2 h-8 w-8"><Edit size={14} /></Button>
                            <Button onClick={() => handleDelete(l.id)} variant="destructive" className="p-2 h-8 w-8"><Trash2 size={14} /></Button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
});

