            setFormData(prev => ({ ...prev, [name]: (e.target as HTMLInputElement).checked }));
        } else {
            setFormData(prev => ({ ...prev, [name]: (name === 'amount' || name === 'interval') ? parseFloat(value) || 0 : value }));
