const ModalManager: React.FC = () => {
    const { activeModal } = useAppState();
    const dispatch = useAppDispatch();
    const closeModal = useCallback(() => dispatch({ type: 'CLOSE_MODAL' }), [dispatch]);

    if (!activeModal) return null;

    const renderModalContent = () => {
        switch (activeModal.type) {
            case 'ADD_TRANSACTION': return { title: "Eintrag", content: <TransactionModal />, size: 'md' as const };
            case 'EDIT_TRANSACTION': return { title: "Bearbeiten", content: <TransactionModal transaction={activeModal.data} />, size: 'md' as const };
            case 'SMART_SCAN': return { title: "KI Beleg-Scan", content: <SmartScanModal />, size: 'lg' as const };
            case 'MANAGE_CATEGORIES': return { title: "Kategorien", content: <CategoryManagerModal />, size: 'lg' as const };
            case 'MANAGE_GOALS': return { title: "Sparziele", content: <GoalManagerModal />, size: 'lg' as const };
            case 'MANAGE_LIABILITIES': return { title: "Schulden", content: <LiabilityManagerModal />, size: 'lg' as const };
            case 'MANAGE_RECURRING': return { title: "Daueraufträge", content: <RecurringManagerModal />, size: 'lg' as const };
            case 'MANAGE_PROJECTS': return { title: "Projekte", content: <ProjectManagerModal />, size: 'md' as const };
            case 'EXPORT_IMPORT_DATA': return { title: "Datentransfer", content: <ExportImportDataModal />, size: 'md' as const };
            case 'TAX_EXPORT': return { title: "Finanzamt-Export", content: <TaxExportModal />, size: 'md' as const };
            case 'SYNC_DATA': return { title: "Synchronisierung", content: <SyncDataModal />, size: 'md' as const };
            case 'MERGE_TRANSACTIONS': return { title: "Zusammenführen", content: <MergeTransactionsModal transactionIds={activeModal.data.transactionIds} />, size: 'md' as const };
            case 'DEBT_PAYDOWN_PLAN': return { title: "Tilgungsplan", content: <DebtPaydownModal />, size: 'xl' as const };
            case 'ANALYSIS': return { title: "Analyse", content: <AnalysisModal />, size: 'xl' as const };
            default: return null;
        }
    };

    const modalProps = renderModalContent();
    if (!modalProps) return null;

    return <Modal title={modalProps.title} onClose={closeModal} size={modalProps.size}>{modalProps.content}</Modal>;
};

export default ModalManager;

import React, { useMemo, useState, useCallback, memo, useRef, useEffect } from 'react';
import { useAppState, useAppDispatch } from '../context/AppContext';
