                </div>
            )}
            {isOffline && (
                <div className="p-3 bg-warning/10 text-warning text-xs font-medium rounded-xl border border-warning/20 flex items-center">
                    <WifiOff className="mr-2 h-4 w-4" /> Du bist offline. KI-Features sind deaktiviert.
