    // PWA App Badging API sync
    useEffect(() => {
        if ('setAppBadge' in navigator) {
            if (dueOrOverdueCount > 0) {
                (navigator as any).setAppBadge(dueOrOverdueCount).catch((e: any) => console.debug('Badge error', e));
            } else {
                (navigator as any).clearAppBadge().catch((e: any) => console.debug('Badge error', e));
            }
        }
    }, [dueOrOverdueCount]);

    // Theme-Color Sync für System-Statusleiste
    useEffect(() => {
        const themeColors: Record<string, string> = {
            grandeur: '#f8fafc',
            synthwave: '#0f0720',
            blockchain: '#0f172a',
            neon: '#0a0a0a',
            forest: '#f1f5f9'
        };
        const color = themeColors[theme] || '#0a0a0a';
        document.getElementById('theme-color-meta')?.setAttribute('content', color);
    }, [theme]);

    // Prevent body scroll when modal is open (Mobile PWA best practice)
    useEffect(() => {
        if (activeModal) {
            document.body.style.overflow = 'hidden';
