// PWA Service Worker Registration
// Wir verwenden einen explizit relativen Pfad './sw.js', um sicherzustellen, dass
// der Browser das Skript gegen den aktuellen Sandbox-Origin auflöst und nicht gegen die ai.studio Domain.
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    // Verwendung von new URL stellt sicher, dass der Pfad absolut zum aktuellen Origin aufgelöst wird
    const swUrl = new URL('./sw.js', window.location.href).href;
    navigator.serviceWorker.register(swUrl)
      .then(registration => {
        console.log('SW registered with scope: ', registration.scope);
      })
      .catch(error => {
        console.error('SW registration failed: ', error);
      });
  });
}

export enum TransactionType {
  INCOME = 'income',
  EXPENSE = 'expense',
  SAVING = 'saving',
}

export enum CategoryType {
  INCOME = 'income',
  EXPENSE = 'expense',
}

export enum GoalType {
  GOAL = 'goal',
  SINKING_FUND = 'sinking_fund',
}

export enum Frequency {
  DAILY = 'daily',
  WEEKLY = 'weekly',
  MONTHLY = 'monthly',
  YEARLY = 'yearly',
}

export enum LiabilityType {
  DEBT = 'debt',
  LOAN = 'loan',
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  description: string;
  date: string;
  categoryId?: string;
  goalId?: string;
  liabilityId?: string;
  tags?: string[];
}

export interface Liability {
  id: string;
  name: string;
  type: LiabilityType;
  initialAmount: number;
  paidAmount: number;
  interestRate: number;
  minMonthlyPayment: number;
}

export interface Category {
  id: string;
  name: string;
  type: CategoryType;
  budget?: number;
}

export interface Goal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
  type: GoalType;
  monthlyContribution?: number;
  startDate?: string;
}

export interface RecurringTransaction {
  id: string;
  description: string;
  amount: number;
  type: TransactionType;
  categoryId?: string;
  goalId?: string;
  frequency: Frequency;
  interval: number;
  startDate: string;
  endDate?: string;
  nextDueDate: string;
  isBill?: boolean;
}

export interface Project {
  id: string;
  name: string;
  incomeBudget?: number;
  expenseBudget?: number;
  tag: string;
}

export interface DashboardStats {
    income: number;
    expense: number;
    saving: number;
    balance: number;
    incomeTrend: number;
    expenseTrend: number;
    savingTrend: number;
